using System.Collections.Concurrent;
using sv_4a5c5e58c14c4d03a186229dc159618e.Models;

namespace sv_4a5c5e58c14c4d03a186229dc159618e.Services;

/// <summary>
/// Singleton store for wizard data, keyed by session ID.
/// Safe for concurrent access across circuits and static SSR requests.
/// </summary>
public class WizardStateStore : IHostedService, IDisposable
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();
    private Timer? _cleanupTimer;

    public WizardState GetOrCreate(string sessionId)
    {
        var state = _states.GetOrAdd(sessionId, _ => new WizardState());
        state.LastAccessed = DateTime.UtcNow;
        return state;
    }

    public WizardState? TryGet(string sessionId)
    {
        if (_states.TryGetValue(sessionId, out var state))
        {
            state.LastAccessed = DateTime.UtcNow;
            return state;
        }
        return null;
    }

    // IHostedService — periodic cleanup of abandoned sessions
    public Task StartAsync(CancellationToken cancellationToken)
    {
        _cleanupTimer = new Timer(_ =>
        {
            var cutoff = DateTime.UtcNow.AddHours(-24);
            foreach (var kvp in _states)
            {
                if (kvp.Value.LastAccessed < cutoff)
                    _states.TryRemove(kvp.Key, out _);
            }
        }, null, TimeSpan.FromMinutes(30), TimeSpan.FromMinutes(30));
        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken)
    {
        _cleanupTimer?.Change(Timeout.Infinite, 0);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _cleanupTimer?.Dispose();
    }
}

using Microsoft.AspNetCore.Components;
using sv_4a5c5e58c14c4d03a186229dc159618e.Models;
using sv_4a5c5e58c14c4d03a186229dc159618e.Services;

namespace sv_4a5c5e58c14c4d03a186229dc159618e.Components.Pages.Apply;

/// <summary>
/// Base class for wizard pages. Resolves the session ID across
/// prerender → interactive transitions using PersistentComponentState.
/// </summary>
public abstract class WizardPageBase : ComponentBase
{
    [Inject] public required WizardStateStore Store { get; set; }
    [Inject] public required IHttpContextAccessor HttpContextAccessor { get; set; }
    [Inject] public required PersistentComponentState PersistentState { get; set; }
    [Inject] public required NavigationManager Nav { get; set; }

    protected string SessionId { get; private set; } = "";
    protected WizardState Wizard { get; private set; } = new();

    /// <summary>Which step (1-4) this page represents.</summary>
    protected abstract int StepNumber { get; }

    protected override void OnInitialized()
    {
        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            SessionId = restored!;
        }
        else
        {
            // During prerender, HttpContext is available
            SessionId = HttpContextAccessor.HttpContext?
                .Items["WizardSessionId"]?.ToString() ?? "";
        }

        Wizard = Store.GetOrCreate(SessionId);
        Wizard.CurrentStep = StepNumber;
    }

    protected void MarkCompleteAndNavigate(string nextUrl)
    {
        Wizard.CompletedSteps.Add(StepNumber);
        Nav.NavigateTo(nextUrl);
    }
}

