@using sv_4a5c5e58c14c4d03a186229dc159618e.Services

@* Static SSR component — rendered in the layout on every navigation *@

@if (_isWizardRoute)
{
    <div class="wizard-progress d-flex align-items-center gap-2 py-2">
        @for (int i = 1; i <= Steps.Length; i++)
        {
            var step = i;
            var isCompleted = _completedSteps.Contains(step);
            var isCurrent = step == _currentStep;
            var cssClass = isCompleted ? "completed" : isCurrent ? "current" : "pending";

            <a href="@Steps[step - 1].Url"
               class="wizard-step @cssClass text-decoration-none d-flex align-items-center gap-1">
                <span class="badge rounded-pill @(isCompleted ? "bg-success" : isCurrent ? "bg-primary" : "bg-secondary")">
                    @(isCompleted ? "✓" : step)
                </span>
                <span class="d-none d-md-inline small">@Steps[step - 1].Label</span>
            </a>

            @if (step < Steps.Length)
            {
                <span class="text-muted">—</span>
            }
        }
        <span class="ms-auto small text-muted">Step @_currentStep of @Steps.Length</span>
    </div>
}

@code {
    private record StepInfo(string Url, string Label);

    private static readonly StepInfo[] Steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review")
    ];

    [Inject] private WizardStateStore Store { get; set; } = default!;
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] private NavigationManager Nav { get; set; } = default!;

    private bool _isWizardRoute;
    private int _currentStep = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var uri = new Uri(Nav.Uri);
        _isWizardRoute = uri.AbsolutePath.StartsWith("/apply/", StringComparison.OrdinalIgnoreCase);

        if (!_isWizardRoute) return;

        var sessionId = HttpContextAccessor.HttpContext?
            .Items["WizardSessionId"]?.ToString();

        if (sessionId is not null)
        {
            var state = Store.TryGet(sessionId);
            if (state is not null)
            {
                _currentStep = state.CurrentStep;
                _completedSteps = state.CompletedSteps;
            }
        }
    }
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_4a5c5e58c14c4d03a186229dc159618e.Components.Pages.Apply

<PageTitle>Apply – Personal Info</PageTitle>
<h1>Step 1: Personal Information</h1>

<div class="col-md-6">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="Wizard.PersonalInfo.Name" @bind:event="oninput" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Wizard.PersonalInfo.Email" @bind:event="oninput" />
    </div>

    <button class="btn btn-primary" @onclick="GoNext" disabled="@(!IsValid)">
        Next: Experience →
    </button>
</div>

@code {
    protected override int StepNumber => 1;
    private bool IsValid => !string.IsNullOrWhiteSpace(Wizard.PersonalInfo.Name)
                         && !string.IsNullOrWhiteSpace(Wizard.PersonalInfo.Email);

    private void GoNext() => MarkCompleteAndNavigate("/apply/experience");
}

@page "/apply/experience"
