@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_4a5c5e58c14c4d03a186229dc159618e.Components.Pages.Apply

<PageTitle>Apply – Personal Info</PageTitle>
<h1>Step 1: Personal Information</h1>

<div class="col-md-6">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="Wizard.PersonalInfo.Name" @bind:event="oninput" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Wizard.PersonalInfo.Email" @bind:event="oninput" />
    </div>

    <button class="btn btn-primary" @onclick="GoNext" disabled="@(!IsValid)">
        Next: Experience →
    </button>
</div>

@code {
    protected override int StepNumber => 1;
    private bool IsValid => !string.IsNullOrWhiteSpace(Wizard.PersonalInfo.Name)
                         && !string.IsNullOrWhiteSpace(Wizard.PersonalInfo.Email);

    private void GoNext() => MarkCompleteAndNavigate("/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_4a5c5e58c14c4d03a186229dc159618e.Components.Pages.Apply
@using sv_4a5c5e58c14c4d03a186229dc159618e.Models

<PageTitle>Apply – Experience</PageTitle>
<h1>Step 2: Work Experience</h1>

<div class="col-md-8">
    @for (int i = 0; i < Wizard.Experience.Jobs.Count; i++)
    {
        var index = i;
        <div class="card mb-3 p-3">
            <div class="d-flex justify-content-between">
                <strong>Job @(index + 1)</strong>
                @if (Wizard.Experience.Jobs.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
                }
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="Wizard.Experience.Jobs[index].Company" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <label class="form-label">Title</label>
                <input class="form-control" @bind="Wizard.Experience.Jobs[index].Title" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="Wizard.Experience.Jobs[index].Duration"
                       @bind:event="oninput" placeholder="e.g. 2020-2023" />
            </div>
        </div>
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add another job</button>

    <div class="d-flex gap-2">
        <a href="/apply/personal-info" class="btn btn-outline-secondary">← Back</a>
        <button class="btn btn-primary" @onclick="GoNext">Next: References →</button>
    </div>
</div>

@code {
    protected override int StepNumber => 2;

    private void AddJob() => Wizard.Experience.Jobs.Add(new JobEntry());
    private void RemoveJob(int index) => Wizard.Experience.Jobs.RemoveAt(index);
    private void GoNext() => MarkCompleteAndNavigate("/apply/references");
}

