using sv_4a5c5e58c14c4d03a186229dc159618e.Components;
using sv_4a5c5e58c14c4d03a186229dc159618e.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();
builder.Services.AddHostedService(sp => sp.GetRequiredService<WizardStateStore>());

var app = builder.Build();

// Assign a session ID cookie for wizard state tracking
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.TryGetValue("WizardSessionId", out var sessionId)
        || string.IsNullOrEmpty(sessionId))
    {
        sessionId = Guid.NewGuid().ToString();
        context.Response.Cookies.Append("WizardSessionId", sessionId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(24)
        });
    }
    context.Items["WizardSessionId"] = sessionId;
    await next();
});

app.UseAntiforgery();

